        deleted_sessions,
        total_sessions_to_delete,
        deleted_local_summaries,
        session_ttl_days = config.lifecycle.session_ttl_days,
        summary_ttl_days = config.lifecycle.summary_ttl_days,
        "Lifecycle cleanup: cycle complete"
    );
    Ok(())
}

