	loading = true;
	error = null;
	authRequired = false;
	try {
		const capabilities = await getApiCapabilities();
		authApiEnabled = capabilities.auth_enabled;
	} catch {
		authApiEnabled = false;
	}

	if (!authApiEnabled) {
		settings = null;
		credentials = [];
		loading = false;
