}

function detectActiveSettingsSection(ids: string[]): string | null {
	if (typeof document === 'undefined') return null;
	const scrollContainer = getSettingsScrollContainer();
	if (!scrollContainer) return ids[0] ?? null;
	const containerTop =
		scrollContainer instanceof Window ? 0 : scrollContainer.getBoundingClientRect().top;
	let current: { id: string; top: number } | null = null;
	let upcoming: { id: string; top: number } | null = null;
	for (const id of ids) {
		const section = document.getElementById(id);
